def seed(conn):
    cur = conn.cursor()
    # Get subject id
    cur.execute("SELECT id FROM subjects WHERE name='AP Geography'")
    row = cur.fetchone()
    if not row:
        cur.execute("INSERT INTO subjects (name) VALUES ('AP Geography')")
        conn.commit()
        cur.execute("SELECT id FROM subjects WHERE name='AP Geography'")
        row = cur.fetchone()
    subject_id = row[0]

    # Upsert chapter note
    cur.execute("SELECT id FROM study_notes WHERE subject_id=? AND chapter_number=12", (subject_id,))
    note = cur.fetchone()
    html_path = "static/notes/ap_geo_ch12_notes.html"
    if note:
        cur.execute(
            "UPDATE study_notes SET chapter_title_en=?, chapter_title_te=?, html_file=? WHERE id=?",
            ("Transportation in AP", "ఆంధ్రప్రదేశ్‌లో రవాణా", html_path, note[0])
        )
    else:
        cur.execute(
            "INSERT INTO study_notes (subject_id, chapter_number, chapter_title_en, chapter_title_te, html_file) VALUES (?,?,?,?,?)",
            (subject_id, 12, "Transportation in AP", "ఆంధ్రప్రదేశ్‌లో రవాణా", html_path)
        )
        conn.commit()
        cur.execute("SELECT id FROM study_notes WHERE subject_id=? AND chapter_number=12", (subject_id,))
        note = cur.fetchone()
    note_id = note[0]
    conn.commit()

    # Clear existing chapter MCQs for this note
    cur.execute("DELETE FROM chapter_mcqs WHERE note_id=?", (note_id,))

    # Insert sections as chapter MCQs (audio sections)
    sections_json = _json.dumps(SECTIONS_JSON, ensure_ascii=False)
    cur.execute(
        "UPDATE study_notes SET sections_json=? WHERE id=?",
        (sections_json, note_id)
    )

    # Insert practice questions
    for sec_idx, diff, q, a, b, c, d, ans, exp in QUESTIONS:
        cur.execute(
            """INSERT INTO chapter_mcqs
               (note_id, section_index, difficulty, question, option_a, option_b, option_c, option_d, answer, explanation)
               VALUES (?,?,?,?,?,?,?,?,?,?)""",
            (note_id, sec_idx, diff, q, a, b, c, d, ans, exp)
        )
    conn.commit()
    print(f"[seed_ap_geo_ch12] Seeded {len(QUESTIONS)} MCQs for Chapter 12 (Transportation in AP)")


if __name__ == "__main__":
    import sqlite3, os
    db = os.path.join(os.path.dirname(__file__), "questions.db")
    conn = sqlite3.connect(db)
    seed(conn)
    conn.close()
